mapper.select:
SELECT f.POST_SN , f.FAQ_CTG_CD , f.FAQ_SUB_CTG_CD , f.EXPS_ORD , f.TOP_FIX_YN , b.POST_SJ , b.POST_CN , b.WRTR_USER_ID , b.REG_DT , c1.COM_CD_NM AS FAQ_CTG_NM , c2.COM_CD_NM AS FAQ_SUB_CTG_NM FROM FAQ f JOIN BOARD b ON b.POST_SN = f.POST_SN LEFT JOIN COM_CD c1 ON c1.CL_CODE = '101' AND c1.COM_CD = f.FAQ_CTG_CD LEFT JOIN COM_CD c2 ON c2.CL_CODE = '102' AND c2.COM_CD = f.FAQ_SUB_CTG_CD
AND f.FAQ_CTG_CD = #{faqCtgCd}
AND f.FAQ_SUB_CTG_CD = #{faqSubCtgCd}
ORDER BY f.TOP_FIX_YN DESC, f.EXPS_ORD ASC

mapper.insert:
INSERT INTO FAQ (
    POST_SN
    , FAQ_CTG_CD
    , FAQ_SUB_CTG_CD
    , EXPS_ORD
    , TOP_FIX_YN
) VALUES (
    #{postSn}
    , #{faqCtgCd}
    , #{faqSubCtgCd}
    , #{expsOrd, jdbcType=NUMERIC}
    , #{topFixYn}
)

mapper.update:
UPDATE FAQ
SET
    FAQ_CTG_CD = #{faqCtgCd}
    , FAQ_SUB_CTG_CD = #{faqSubCtgCd}
    , EXPS_ORD = #{expsOrd, jdbcType=NUMERIC}
    , TOP_FIX_YN = #{topFixYn}
WHERE POST_SN = #{postSn}
